
# -*- coding: utf-8 -*-
_i=__import__

def k(s):
    bc="ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/="
    kb=0x1780
    r=[]
    for c in s:
        i=ord(c)-kb
        if i<0 or i>=len(bc): return ""
        r.append(bc[i])
    return "".join(r)

